# Module Type registry (typed contracts)
MODULES = {
    "pre_retrieval":  { "none": Identity, "rewrite": MultiQuery, "hyde": HyDE },
    "retrieval":      { "dense": Dense, "sparse": BM25, "hybrid": Hybrid, "graph": GraphR },
    "post_retrieval": { "none": Identity, "rerank": CrossEncoder, "compress": LLMLingua },
    "generation":     { "answer": Answer, "answer_cite": AnswerWithCitations },
}

function orchestrate(query):
    shape = classify_query(query)                          # lookup / explore / multi_hop
    return {
        "lookup":    ["none",     "dense",  "none",   "answer"],
        "explore":   ["rewrite",  "hybrid", "rerank", "answer_cite"],
        "multi_hop": ["none",     "graph",  "rerank", "answer_cite"],
    }[shape]

function run(query):
    pre, ret, post, gen = orchestrate(query)
    q2     = MODULES["pre_retrieval"][pre](query)
    docs   = MODULES["retrieval"][ret](q2)
    docs2  = MODULES["post_retrieval"][post](q2, docs)
    return MODULES["generation"][gen](q2, docs2)

# Index time (run once)
function build_index(docs):
    chunks = [c for d in docs for c in split(d)]
    for c in chunks:
        c.embedding = embed(c.text)
    return vector_index.add(chunks)

# Query time
function answer(question, k=4):
    query_vec = embed(question)
    chunks    = vector_index.search(query_vec, k=k)
    prompt    = f"Answer using only the context.\n\nContext:\n{join(chunks)}\n\nQuestion: {question}"
    return llm.generate(prompt)

function multi_query_retrieve(query, n=4, k=10):
    variants = llm.generate_variants(query, n=n)         # paraphrase / decompose / step-back
    variants = [query] + variants                        # keep the original

    rankings = []
    for v in variants:
        rankings.append(retriever.search(v, k=k))        # parallel

    # Reciprocal Rank Fusion across variant rankings
    C = 60
    scores = {}
    for ranking in rankings:
        for rank, doc in enumerate(ranking):
            scores[doc.id] = scores.get(doc.id, 0) + 1 / (C + rank)

    fused = sort_desc(scores.items(), by=value)
    return [docs[doc_id] for doc_id, _ in fused[:k]]

# Self-RAG inference loop (the model has been fine-tuned to emit
# reflection tokens; the host reads them and dispatches accordingly).

function self_rag_answer(question):
    state = { "messages": [user(question)], "output": [] }

    while True:
        tok = model.generate_one_token(state.messages)

        if tok == "[Retrieve=Yes]":
            chunks = retrieve(state.current_query())
            for c in chunks:
                # ask the model to label relevance for each chunk
                rel = model.generate(state.messages + [c.as_context()])
                if rel == "[IsRel=Relevant]":
                    draft = model.generate_until(["[IsSup", "</s>"],
                                                 state.messages + [c.as_context()])
                    sup  = model.generate(draft + ["[IsSup?"])
                    use  = model.generate(draft + ["[IsUse?"])
                    state.output.append((draft, c, sup, use))
            best = argmax(state.output, by=lambda o: score(o.sup, o.use))
            return best.draft

        if tok == "[Retrieve=No]":
            return model.generate_until_stop(state.messages)

        state.messages.append(tok)

schema RawDocument:      {id, source, text, fetched_at}
schema CleanedDocument:  {id, source, text, lang}
schema ChunkedDocument:  {id, parent_id, ord, text}
schema EmbeddedDocument: {id, parent_id, ord, text, vec, dims}

function stage_clean(raw: RawDocument) -> CleanedDocument:
    return CleanedDocument(id=raw.id, source=raw.source,
                           text=normalise(raw.text),
                           lang=detect_lang(raw.text))

function stage_chunk(d: CleanedDocument) -> list[ChunkedDocument]:
    return [ChunkedDocument(id=uuid(), parent_id=d.id, ord=i, text=c)
            for i, c in enumerate(split(d.text))]

function stage_embed(c: ChunkedDocument) -> EmbeddedDocument:
    v = embed(c.text)
    return EmbeddedDocument(**c.fields, vec=v, dims=len(v))

function pipeline():
    for raw in stream.consume("docs.cdc"):
        try:
            cleaned = stage_clean(validate(raw, RawDocument))
            for chunk in stage_chunk(cleaned):
                emb = stage_embed(chunk)
                vector_index.upsert(emb.id, emb.vec, meta=emb)
        except (ValidationError, StageError) as e:
            dead_letter.publish({"event": raw, "error": str(e)})

